CREATE TABLE IF NOT EXISTS support_measures (id SERIAL PRIMARY KEY, code VARCHAR(80) UNIQUE NOT NULL, title VARCHAR(300) NOT NULL, short_description TEXT NOT NULL, full_description TEXT, category VARCHAR(40) NOT NULL, level VARCHAR(20) NOT NULL DEFAULT 'federal', region_code VARCHAR(10), amount_text VARCHAR(200), amount_min INTEGER, amount_max INTEGER, frequency VARCHAR(40), min_children INTEGER DEFAULT 0, max_children INTEGER, requires_low_income BOOLEAN DEFAULT FALSE, requires_many_children BOOLEAN DEFAULT FALSE, requires_pregnancy BOOLEAN DEFAULT FALSE, requires_single_parent BOOLEAN DEFAULT FALSE, requires_disability BOOLEAN DEFAULT FALSE, requires_military_family BOOLEAN DEFAULT FALSE, requires_student BOOLEAN DEFAULT FALSE, requires_mortgage BOOLEAN DEFAULT FALSE, child_age_min INTEGER, child_age_max INTEGER, parent_age_min INTEGER, parent_age_max INTEGER, apply_url VARCHAR(500), legal_source VARCHAR(300), documents_required JSONB DEFAULT '[]'::jsonb, how_to_apply JSONB DEFAULT '[]'::jsonb, deadline_text VARCHAR(200), icon VARCHAR(60) DEFAULT 'Gift', is_active BOOLEAN DEFAULT TRUE, priority INTEGER DEFAULT 50, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP);